        tpl: '<header>\r\n  <a href="#top" accesskey="T" id="top" :title="$t(\'mainPart.top\')">:::</a>\r\n  <a\r\n    v-if="ct$currentSite.showlogin && !ct$isLogin"\r\n    :href="ct$loginUrl"\r\n    v-t="\'mainPart.login\'"\r\n  ></a>\r\n  <a v-if="ct$isLogin" :href="ct$logoutUrl" v-t="\'mainPart.logout\'"></a>\r\n  <a\r\n    href="#sitemap"\r\n    @click="$emit(\'update:page\', \'focusedPage\',\'sitemap\')"\r\n    v-t="\'mainPart.guidedtour\'"\r\n  ></a>\r\n  <div\r\n    v-if="ct$siteserver.langs.length > 1"\r\n    :class="{ \'active\' : langHasFocus }"\r\n    @focusin="langHasFocus = true"\r\n    @focusout="langHasFocus = false"\r\n    class="dropdown"\r\n  >\r\n    <div class="dropbtn">\r\n      <a href="#">\r\n        Language Select\r\n        <ct-svg\r\n          key="angle-down"\r\n          class="line-block"\r\n          alt="angle-down"\r\n          svg-src="/pkg_nss/63e486d710f5db1511a7215e/img/angle-down.svg"\r\n        ></ct-svg>\r\n      </a>\r\n    </div>\r\n    <div class="dropdown-content">\r\n      <a href="/nss/p/index">Chinese</a>\r\n      <template v-for="item in languageHandler">\r\n        <a\r\n          href="#"\r\n          @click.prevent="$emit(\'update:lang\', \'language\', item)"\r\n          v-t="\'mainPart.\' + item"\r\n          :title="$t(\'mainPart.switchInterface-\' + item)"\r\n        ></a>\r\n      </template>\r\n\r\n      <template v-for="item in subSiteLanguageHandler">\r\n        <a :href="`/nss/s/${item.upath}`">{{ item.lang }}</a>\r\n      </template>\r\n      <a href="/nss/s/JAPAN">Japanese</a>\r\n    </div>\r\n  </div>\r\n  <div class="fontsize">\r\n    <button\r\n      @click="setFontSize(\'0.9rem\')"\r\n      v-t="\'mainPart.small\'"\r\n      title="字級-小"\r\n    ></button>\r\n    <button\r\n      @click="setFontSize(\'1rem\')"\r\n      v-t="\'mainPart.middle\'"\r\n      title="字級-中"\r\n    ></button>\r\n    <button\r\n      @click="setFontSize(\'1.1rem\')"\r\n      v-t="\'mainPart.large\'"\r\n      title="字級-大"\r\n    ></button>\r\n  </div>\r\n\r\n  <div class="searchBlock">\r\n    <form\r\n      class="ct-row gd-xs12"\r\n      style="display: flex; margin-bottom: 0"\r\n      action="srh"\r\n      method="GET"\r\n      target="_blank"\r\n    >\r\n      <div class="line-block">\r\n        <div class="search-inline" style="padding-left: 0px">\r\n          <input\r\n            name="_keyword"\r\n            type="text"\r\n            id="ck_"\r\n            required="required"\r\n            :title="$t(\'mainPart.GA017_001\')"\r\n            :laceholder="$t(\'mainPart.GA017_002\')"\r\n            remark="輸入搜尋關鍵字"\r\n          />\r\n          <label for="ck_" class="input-label"></label>\r\n          <i class="bar"></i>\r\n        </div>\r\n      </div>\r\n      <button\r\n        class="ct-btn btn-xs radius-n ct-ripple btn-all btn-Muted"\r\n        type="submit"\r\n        remark="搜尋"\r\n        key="searchBtn"\r\n      >\r\n        <span>搜尋</span>\r\n      </button>\r\n    </form>\r\n  </div>\r\n</header>\r\n',
