          tpl: '<div ref="top">\n  <div class="ct-resource gd-xs12">\n    <div class="subpage-top bg-fresh text-primary text-l m-b-sm">\n      <h3 v-t="\'GA019067\'" remark="查看訂閱名單"></h3>\n    </div>\n    <small>編輯信箱後鍵入Enter即可完成更改，儲存後生效。</small>\n    <div class="bg-fresh text-l m-t-sm">\n      <ul class="ct-nav nav-tabs" style=" white-space: nowrap; overflow: hidden; border:none">\n        <li class="nav-item tdset">\n          <a class="nav-link tabw" :class="{active: isSubscribeTab}" @click="tab=\'subscribe\'" remark="使用者訂閱">{{ textSubscripbeTab }}</a>\n        </li>\n        <li class="nav-item tdset">\n          <a class="nav-link tabw" :class="{active: isAdminImportTab}" @click="tab=\'admin-import\'" remark="管理者匯入">{{ textAdminImportTab }}</a>\n        </li>\n      </ul>\n      <button @click="onClickDeleteSelected" class="m-r-xs ct-btn btn-md radius-xs btn-danger ct-ripple btn-right" v-t="\'GA019076\'" remark="刪除已勾選項目" :disabled="!selected.length"></button>\n      <button @click="onClickDeleteAll" v-show="isAdminImportTab" class="m-r-xs ct-btn btn-md radius-xs btn-danger ct-ripple btn-right" remark="刪除全部">{{ textDeleteAll }}</button>\n      <button @click="onClickExport" class="m-r-xs ct-btn btn-md radius-xs btn-confirm ct-ripple btn-right" v-t="\'GA019069\'" remark="匯出"></button>\n      <input v-model="text" class="m-r-xs p-t-xxs p-b-xxs btn-right" placeholder="搜尋"></input>\n    </div>\n    <div class="table-responsive">\n      <table class="ct-table table-striped table-hover">\n        <thead class="thead-light">\n          <tr>\n            <th scope="col" style="width: 10%" class="p-l">\n              <div @click.stop class="ct-checkbox-m ct-checkbox-inline-m m-r-sm float-l">\n                <input v-uni-id="\'checkbox-all\'" type="checkbox" v-model="checkAllCheckbox">\n                <label v-uni-for="\'checkbox-all\'"></label>\n              </div>\n            </th>\n            <th scope="col" style="width: 80%" class="p-l">Email</th>\n            <th scope="col" style="width: 80%" class="p-l" v-t="\'GA019081\'" remark="操作"></th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr v-for="item in list" :key="item.id">\n            <td style="width:10%">\n              <div class="ct-checkbox-m ct-checkbox-inline-m m-r-sm float-l">\n                <input v-uni-id="item.id" type="checkbox" v-model="selected" :value="item.id">\n                <label v-uni-for="item.id"></label>\n              </div>\n            </td>\n            <td data-column="email" style="width:80%">\n              <input v-if="item.showInput" v-model="item.value" @keydown.enter="$set(item, \'showInput\', false)"></input>\n              <div v-else>{{ item.value }}</div>\n              <!--div v-if="memberPageList === \'subscribe\'" class="form-group-m m-no">\n                <input v-if="editList.indexOf(emailPage*10 + index) > -1" type="text" v-model="emailList.sub[emailPage*10 + index]" :id="sid+index+\'email\'" style="border-bottom: 2px gray solid;"></input>\n                  <div v-else>{{email}}</div>\n              </div>\n              <div v-if="memberPageList === \'admin\'" class="form-group-m m-no">\n                <input v-if="editList.indexOf(emailPage*10 + index) > -1" type="text" v-model="emailList.admin[emailPage*10 + index]" :id="sid+index+\'email\'" style="border-bottom: 2px gray solid;"></input>\n                <div v-else>{{email}}</div>\n              </div-->\n            </td>\n            <td>\n              <a v-if="item.showInput" style="color:#3e74ce;width:10%;" @click.prevent="$set(item, \'showInput\', false)">確認</a>\n              <a v-else style="color:#3e74ce;width:10%;" @click.prevent="$set(item, \'showInput\', true)">編輯</a>\n            </td>\n          </tr>\n          <tr>\n            <td v-if="!list.length" colspan="3" v-t="\'GA019077\'" remark="無資料"></td>\n          </tr>\n        </tbody>\n      </table>\n    </div>\n    <div class="float-r btn-group" v-if="targetList.length">\n      <button type="button" title="上一頁" remark="上一頁" class="ct-btn btn-sm btn-line btn-secondary" @click="onClickSetPage(page-1)" v-t="\'GA019070\'" :disabled="page===1"></button>\n      <button v-for="n in ArrayOfPage" :key="n" type="button" class="ct-btn btn-sm btn-line btn-secondary" :class="{active: n===page}" @click="onClickSetPage(n)">{{ n }}</button>\n      <button type="button" title="下一頁" remark="下一頁"class="ct-btn btn-sm btn-line btn-secondary" @click="onClickSetPage(page+1)" v-t="\'GA019071\'" :disabled="page===MaxPage"></button>\n    </div>\n  </div>\n  <button @click="onClickSubmit" class="m-r-xs ct-btn btn-md radius-xs btn-confirm ct-ripple" v-t="\'GA019038\'" remark="儲存"></button>\n  <button @click="onClickCancel" class="m-r-xs ct-btn btn-md radius-xs btn-secondary ct-ripple" v-t="\'GA019002\'" remark="取消"></button>\n</div>',
