          tpl: '<div ref="top">\n  <div class="ct-resource gd-xs12">\n    <div class="bg-fresh text-primary text-l">\n      <h3 v-t="\'GA019073\'" remark="管理者匯入"></h3>\n      <p class="text-secondary" v-t="\'GA019080\'" remark="匯入檔案請上傳csv檔，格式可參照範例檔(點選右方按鈕下載)"></p>\n    </div>\n    <div class="subpage-top bg-fresh text-l">\n      <h4 class="inline-block text-primary m-r" v-t="\'GA019074\'" remark="匯入人數"></h4>\n      <p class="inline-block" v-show="MaxPage">{{ counts }}</p>\n      <button @click="onClickOpenFileSelector" class="m-r-xs ct-btn btn-md radius-xs btn-confirm ct-ripple btn-right" v-t="\'GA019075\'" remark="匯入"></button>\n      <button type="submit" class="m-r-xs ct-btn btn-md radius-xs btn-confirm ct-ripple btn-right">\n        <a :href="ExampleFileUri" download="電子報信箱範例.csv" style="color:#ffffff" v-t="\'GA019079\'" remark="下載範例檔案"></a>\n      </button>\n      <button @click="onClickDeleteSelected" class="m-r-xs ct-btn btn-md radius-xs btn-danger ct-ripple btn-right" v-t="\'GA019076\'" remark="刪除已勾選項目" :disabled="!selected.length"></button>\n      <input ref="fileInput" @change="onSelectFileChange" accept=".csv" type="file" style="display: none;" />\n    </div>\n    <div class="table-responsive">\n      <table class="ct-table table-striped table-hover">\n        <thead class="thead-light">\n          <tr>\n            <th scope="col" style="width: 10%" class="p-l">\n              <div class="ct-checkbox-m ct-checkbox-inline-m m-r-sm float-l">\n                <input v-uni-id="\'GA019-import-check-all\'" v-model="checkAllCheckbox" type="checkbox" />\n                <label v-uni-for="\'GA019-import-check-all\'"></label>\n              </div>\n            </th>\n            <th scope="col" style="width: 90%" class="p-l">Email</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr v-for="item in list" :key="item.id">\n            <td>\n              <div class="ct-checkbox-m ct-checkbox-inline-m m-r-sm float-l">\n                <input v-uni-id="item.id" :value="item.id" v-model="selected" type="checkbox" />\n                <label v-uni-for="item.id"></label>\n              </div>\n            </td>\n            <td :data-column="item.value">\n              <div class="form-group-m m-no">\n                <div>{{ item.value }}</div>\n                <!--label :for="sid+index+\'email\'" class="input-label"></label-->\n              </div>\n            </td>\n          </tr>\n          <tr v-if="counts===0">\n            <td colspan="2" v-t="\'GA019077\'" remark="無資料"></td>\n          </tr>\n        </tbody>\n      </table>\n    </div>\n    <div v-if="MaxPage>1" class="float-r btn-group">\n      <button @click="onClickSetPage(page-1)" type="button" :title="$t(\'GA019070\')" remark="上一頁" class="ct-btn btn-sm btn-line btn-secondary" :disabled="page===1">&lt;</button>\n      <button v-for="n in ArrayOfPage" :key="n" @click="onClickSetPage(n)" type="button" class="ct-btn btn-sm btn-line btn-secondary" :class="{active: page===n}">{{ n }}</button>\n      <button @click="onClickSetPage(page+1)" type="button" :title="$t(\'GA019071\')" remark="下一頁" class="ct-btn btn-sm btn-line btn-secondary" :disabled="page===MaxPage">&gt;</button>\n    </div>\n    <!--div class="btn-right">\n      <button type="submit" class="m-r-xs ct-btn btn-md radius-xs btn-confirm ct-ripple">{{$t(\'g70\')}}</button>\n      <button type="submit" class="m-r-xs ct-btn btn-md radius-xs btn-confirm ct-ripple">{{$t(\'g71\')}}</button>\n    </div-->\n  </div>\n  <button @click="onClickSubmit" class="m-r-xs ct-btn btn-md radius-xs btn-confirm ct-ripple" v-t="\'GA019038\'" remark="儲存"></button>\n  <button @click="onClickCancel" class="m-r-xs ct-btn btn-md radius-xs btn-secondary ct-ripple" v-t="\'GA019002\'" remark="取消"></button>\n</div>',
