          cts: '"use strict";var allowdModuleIds=["5d355adc3c55824e3810cdcc"],ItemPerPage=20;module.exports.props={mid:String,sid:String},module.exports.data=function(){return{page:1,counts:0,freshCodes:[],codes:[],state:"",input:""}},module.exports.computed={MaxPage:function(){return Math.ceil(this.counts/ItemPerPage)}},module.exports.methods={fetch:function(){var a=this,b={number:ItemPerPage,page:this.page};return b.match={tag:"code"},this.api$findStorage(b).then(function(b){var c=b.options;this.counts=c.count;var d=b.result.map(function(b){var c=b.data,d=c.code,e=a.api$decodeToken(d);return{id:b._id,code:d,site:e.sname,page:e.pname,name:e.mname,valid:-1!==allowdModuleIds.indexOf(e.api.mid)}}).filter(function(a){return a.valid});a.codes=d})},onClickInsertCode:function(){if(""===this.state){this.state="halt";var a=this,b=this.input;return this.api$findStorage({query:[{tag:"code",or:[{v:2,code:b},{importCode:b}]}]}).then(function(c){var d=c.options;if(0!==d.count)return void(a.state="duplicate");var e=a.api$decodeToken(b);return-1===allowdModuleIds.indexOf(e.api.mid)?void(a.state="typeError"):void(a.freshCodes.push({code:b,site:e.sname,page:e.pname,name:e.mname,valid:!0}),a.input=a.state="")})}},onClickDeleteCode:function(a){var b=this,c={v:2,code:a.code};return a.id?this.api$setOneIntoStorage(c,{destroyed:!0},a.id).then(function(){return b.page=1,b.fetch()}):void(this.freshCodes=this.freshCodes.filter(function(b){return b.code!==a.code}))},onClickCancel:function(){this.$emit("done",!1)},onClickSubmit:function(){var a=this,b=this.freshCodes.map(function(b){var c=b.code;return a.api$setOneIntoStorage({v:2,code:c,tag:"code"})});return Promise.all(b).then(function(){a.$emit("done",!0)})}},module.exports.mounted=function(){this.fetch()},module.exports.watch={input:function(a){if(this.state="",!!a)try{var b=this.api$decodeToken(a),c=b.api;if(-1===allowdModuleIds.indexOf(c.mid))return void(this.state="typeError")}catch(a){this.state="invalid"}}};',
          tpl: '<div class="modal-mask-detail">\n  <div class="modal-wrapper-detail">\n    <div class="modal-container-detail ">\n      <div class="ct-resource gd-xs12">\n        <div class="subpage-top bg-fresh text-primary text-l">\n          <h3 v-t="\'GA019060\'" remark="添加電子報索引引用代碼"></h3>\n        </div>\n        <div class="form-inline m-t-md p-l-sm">\n          <div class="form-group-m" :class="{\'states-danger-m\': state!==\'\'}">\n            <input v-uni-id="\'input-code\'" v-model.trim="input" type="text" :title="$t(\'GA019061\')" />\n            <label v-uni-for="\'input-code\'" class="input-label" v-t="\'GA019061\'" remark="輸入電子報索引引用代碼"></label>\n            <i class="bar"></i>\n            <div v-show="state===\'empty\'" class="feedback" v-t="\'GA019064\'" remark="引用代碼不可空白"></div>\n            <div v-show="state===\'halt\'" class="feedback" remark="驗證中">驗證中</div>\n            <div v-show="state===\'invalid\'" class="feedback" remark="代碼格式錯誤">代碼格式錯誤</div>\n            <div v-show="state===\'duplicate\'" class="feedback" v-t="\'GA019064-1\'" remark="重複引用"></div>\n            <div v-show="state===\'noAnno\'" class="feedback" v-t="\'GA019064-2\'" remark="請先建立索引後再進行導入"></div>\n            <div v-show="state===\'typeError\'" class="feedback" v-t="\'GA019064-3\'" remark="只可導入電子報索引的引用代碼"></div>\n          </div>\n          <button @click="onClickInsertCode" :disabled="state!==\'\'" class="ct-btn btn-sm btn-min-xs radius-xs btn-confirm ct-ripple oline-no" v-t="\'GA019062\'"></button>\n        </div>\n        <div class="table-responsive table-manage">\n          <table class="ct-table table-striped table-hover">\n            <thead class="thead-light">\n              <tr>\n                <th remark="站台名稱" width="30%">站台名稱</th>\n                <th remark="頁面名稱" width="30%">頁面名稱</th>\n                <th remark="模組名稱" width="30%">模組名稱</th>\n                <th width="10%">操作</th>\n              </tr>\n            </thead>\n            <tbody>\n              <tr v-for="item in freshCodes">\n                <td data-label="unit" class="noticedatatitle" remark="站台名稱">{{ item.site }}</td>\n                <td class="noticedatatitle" remark="頁面名稱">{{ item.page }}</td>\n                <td class="noticedatatype" remark="模組名稱">{{ item.name }}</td>\n                <td data-label="delete" class="noticedatadel" remark="移除">\n                  <button @click.prevent.stop="onClickDeleteCode(item)" class="ct-btn btn-secondary btn-line btn-xs" style="margin-left: 8px;" alt="移除" title="移除" remark="移除">X</button>\n                </td>\n              </tr>\n            </tbody>\n            <tbody>\n              <!--每5筆換頁-->\n              <tr v-for="item in codes">\n                <td data-label="unit" class="noticedatatitle" remark="站台名稱">{{ item.site }}</td>\n                <td class="noticedatatitle" remark="頁面名稱">{{ item.page }}</td>\n                <td class="noticedatatype" remark="模組名稱">{{ item.name }}</td>\n                <td data-label="delete" class="noticedatadel" remark="移除">\n                  <button @click.prevent.stop="onClickDeleteCode(item)" class="ct-btn btn-secondary btn-line btn-xs" style="margin-left: 8px;" alt="移除" title="移除" remark="移除">X</button>\n                </td>\n              </tr>\n              <tr>\n                <td v-if="!(codes.length||freshCodes.length)" colspan="4" v-t="\'GA019077\'" remark="無資料"></td>\n              </tr>\n            </tbody>\n          </table>\n        </div>\n        <!--div v-show="MaxPage>1" class="ct-row gd-md12 m-b p-r-sm">\n          <div class="float-r btn-group">\n            <button type="button" class="ct-btn btn-sm btn-line btn-secondary">&lt;</button>\n            <button type="button" class="ct-btn btn-sm btn-line btn-secondary">1</button>\n            <button type="button" class="ct-btn btn-sm btn-line btn-secondary">&gt;</button>\n          </div>\n        </div-->\n        <div class="gd-xs12 text-c">\n          <button @click.stop="onClickCancel" remark="取消" class="ct-btn btn-md radius-xs btn-secondary m-r ct-ripple">\n            <ct-svg class="m-r-xs line-block" svg-src="/pkg_nss/5be4fba5fbad014360edffa1/assets/cancel-m.svg"></ct-svg>\n            {{ $t(\'GA019058\') }}\n          </button>\n          <button @click.prevent.stop="onClickSubmit" v-show="freshCodes.length" remark="發布" class="ct-btn btn-md radius-xs btn-confirm ct-ripple">\n            <ct-svg class="m-r-xs line-block" svg-src="/pkg_nss/5be4fba5fbad014360edffa1/assets/confirm-m.svg"></ct-svg>\n            {{$t(\'GA019059\')}}\n          </button>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>',
