          name: "headerFooterStage",
          cts: '"use strict";module.exports.props={mid:String,sid:String},module.exports.data=function(){return{singleData:{admin:[],visitor:[],header:{image:""},footer:{issuer:"",phone:"",address:"",mail:"",copyright:""}}}},module.exports.methods={onClickCancel:function(){this.$emit("done",!1)},onClickSubmit:function(){var a=this,b={isPartial:!0,"data.footer":this.singleData.footer,"data.header":this.singleData.header};this.api$setStorage(b).then(function(){a.$emit("done",!0)})},getSingle:function(){var a=this;this.api$getStorage().then(function(b){a.singleData=Object.assign(a.singleData,b.data)})},imgInputChange:function(a){var b=a.target.files[0],c=this;b&&this.api$uploadFile(b).then(function(a){c.singleData.header.image=a})},chooseCoverImg:function(){this.$refs.coverImgInput.click()},cancelCoverImg:function(){this.singleData.header.image=""}},module.exports.mounted=function(){this.getSingle()};',
          tpl: '<div class="modal-mask-detail">\n  <div class="modal-wrapper-detail">\n    <div class="modal-container-detail">\n      <div class="ct-row">\n        <div class="gd-xs12">\n          <div class="bg-fresh text-primary">\n            <h3 class="p" remark="上傳刊頭圖片">上傳刊頭圖片</h3>\n          </div>\n          <p class="p-l help-block">建議尺寸:寬800px 高150px，大小2MB以下，若超過則自動壓縮</p>\n          <input\n            @change="imgInputChange"\n            ref="coverImgInput"\n            type="file"\n            accept=".jpg,.jpeg,.bmp,.png,.svg"\n            id="coverImgInput"\n            style="display: none;"\n            remark="請選擇圖片"\n          />\n          <div v-if="!singleData.header.image" class="coverImgEmpty m">\n            <img src="/src/images/ga019-banner.jpg" alt="刊頭預設圖片">\n            <div class="pencil" @click="chooseCoverImg">\n              <ct-svg svg-src="/pkg_nss/5be4fba5fbad014360edffa1/assets/pencil.svg"></ct-svg>\n            </div>\n          </div>\n          <div v-else class="coverImg m" remark="相片">\n            <img :src="singleData.header.image" alt="刊頭圖片"/>\n            <div class="pencil" @click="chooseCoverImg">\n              <ct-svg svg-src="/pkg_nss/5be4fba5fbad014360edffa1/assets/pencil.svg" ></ct-svg>\n            </div>\n            <div class="cross" @click="cancelCoverImg">\n              <ct-svg svg-src="/pkg_nss/5be4fba5fbad014360edffa1/assets/cross.svg" ></ct-svg>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div class="ct-row">\n        <div class="gd-xs12">\n          <div class="bg-fresh text-primary">\n            <h3 class="p" remark="設定頁尾資料">設定頁尾資料</h3>\n          </div>\n        </div>\n      </div>\n      <div class="ct-row">\n        <form class="m-l">\n          <div class="form-flex">\n            <div class="form-group-m">\n              <input type="text" id="issuer" v-model="singleData.footer.issuer" required>\n              <label for="issuer" class="input-label">發行單位</label>\n              <i class="bar"></i>\n            </div>\n            <div class="form-group-m ">\n              <input type="text" id="phone" v-model="singleData.footer.phone" required>\n              <label for="phone" class="input-label">聯絡電話</label>\n              <i class="bar"></i>\n            </div>\n          </div>\n          <div class="form-flex">\n            <div class="form-group-m">\n              <input type="text" id="address" v-model="singleData.footer.address" required>\n              <label for="address" class="input-label">聯絡地址</label>\n              <i class="bar"></i>\n            </div>\n            <div class="form-group-m">\n              <input type="text" id="mail" v-model="singleData.footer.mail" required>\n              <label for="mail" class="input-label">聯絡信箱</label>\n              <i class="bar"></i>\n            </div>\n          </div>\n          <div class="form-flex">\n            <div class="form-group-m gd-xs5">\n              <input type="text" id="copyright" v-model="singleData.footer.copyright" required>\n              <label for="copyright" class="input-label">版權宣告</label>\n              <i class="bar"></i>\n            </div>\n          </div>\n        </form>\n      </div>\n      <div class="ct-row">\n        <div class="gd-xs12 text-c">\n          <button @click.stop="onClickCancel" remark="取消" class="ct-btn btn-md radius-xs btn-secondary m-r ct-ripple">\n            <ct-svg class="m-r-xs line-block" svg-src="/pkg_nss/5be4fba5fbad014360edffa1/assets/cancel-m.svg"></ct-svg>\n            {{ $t(\'GA019058\') }}\n          </button>\n          <button @click.stop="onClickSubmit" remark="發布" class="ct-btn btn-md radius-xs btn-confirm ct-ripple">\n            <ct-svg class="m-r-xs line-block" svg-src="/pkg_nss/5be4fba5fbad014360edffa1/assets/confirm-m.svg"></ct-svg>\n            {{$t(\'GA019059\')}}\n          </button>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>\n\n',
