          tpl: '<div>\n  <div class="ct-row text-r">\n    <div class="tool-search-block m-b-xs">\n      <div class="form-group-m keyword" style="margin: 0;">\n        <div class="svg-inline">\n          <ct-svg svg-src="/pkg_nss/5abf2d62aa93092cee58ceb4/assets/search.svg" key="search"></ct-svg>\n        </div>\n        <label v-uni-for="\'input-keyword\'" class="label-hide">標題、關鍵字</label>\n        <input\n          ref="start"\n          @keyup.enter="emitKeyword"\n          v-uni-id="\'input-keyword\'"\n          type="text"\n          v-model="keyword"\n          style="padding-left: 20px;"\n          :placeholder="$t(\'tl001\')"\n          :title="`${moduleName} ${$t(\'tl001\')}`"\n          :alt="`${moduleName} ${$t(\'tl001\')}`"\n          remark="請輸入關鍵字"\n        />\n        <i class="bar"></i>\n      </div>\n\n    </div>\n    <div class="tool-block">\n      <div class="tool-select-block">\n        <div @click.stop class="float-l m-l-xs">\n          <button\n            type="button"\n            :title="$t(\'tl009\')"\n            @click.stop="updateOpenMenu(\'anno-group\')"\n            class="ct-btn btn-sm btn-Muted radius-xs ct-dropdown-toggle"\n            remark="發布單位"\n          >\n            {{ filteringByGroupPrompt }}\n          </button>\n          <div\n            :class="{\'menu-visible\':openMenu==\'anno-group\'}"\n            class="dropdown-container-m "\n          >\n            <ul class="dropdown-menu-m" style="max-height: 215px; overflow-y: auto;">\n              <li\n                @click="onClickSelectGroup()"\n                :class="{\'selected ct-ripple\':!filtGroup}"\n                class="dropdown-item-m"\n              >\n                <a\n                  href="#"\n                  style="color: #7e7e7e;"\n                  @click.prevent\n                  remark="全部"\n                  v-t="\'tl004\'"\n                  role="button"\n                ></a>\n              </li>\n              <li\n                @click="onClickSelectGroup(item)"\n                v-for="item in importGroups"\n                :class="{\'selected ct-ripple\':item==filtGroup}"\n                class="dropdown-item-m"\n              >\n                <a href="#" role="button" style="color: #7e7e7e;" @click.prevent>{{\n                  item.name\n                }}</a>\n              </li>\n            </ul>\n          </div>\n        </div>\n      </div>\n\n      <!-- RSS訂閱 -->\n      <div class="tool-btn-block">\n        <a\n          :href="rssLink"\n          target="_system"\n          type="button"\n          class="ct-btn btn-sm btn-Muted radius-xs m-l-xs float-l ct-ripple"\n          :title="moduleName+\'RSS訂閱\' + $t(\'newTab\')"\n          aria-label="RSS訂閱"\n          @focus="closeAnnoGroup"\n        >\n          <ct-svg\n            style="margin: -5px; height: 30px; padding-top: 2px;"\n            svg-src="/pkg_nss/5abf2d62aa93092cee58ceb4/assets/rss_feed.svg"\n            key="rss"\n          ></ct-svg>\n\t\t    <span class="sr-only">RSS訂閱</span>\n        </a>\n\n    \n        \n        <!-- toolbar 設定  button -->\n        <button\n          v-if="edit"\n          type="button"\n          @click="showAdvMenu=!showAdvMenu"\n          class="ct-btn btn-sm btn-primary radius-xs m-l-xs float-l ct-ripple"\n          remark="設定"\n          v-t="\'tl002\'"\n        ></button>\n      </div>\n    </div>\n  </div>\n\n\n  <div v-if="showAdvMenu" class="ct-row notice_setting m-b-xs gd-md12">\n    <!--div class="float-r" style="margin-left: 10px;">\n\t\t\t<button type="button" @click="$emit(\'importCode\')" class="ct-btn btn-sm btn-white radius-xs" v-t="\'tl007\'" remark="引用代碼"></button>\n\t\t</div-->\n    <div v-if="ctrl" class="float-r" style="margin-left: 10px;">\n      <button\n        type="button"\n        @click="$emit(\'modifyTags\')"\n        class="ct-btn btn-sm btn-white radius-xs"\n        v-t="\'設定分類\'"\n        remark="設定分類"\n      ></button>\n    </div>\n    <div class="float-r">\n      <button\n        @click.stop="updateOpenMenu(\'modifyIPP\')"\n        type="button"\n        class="ct-btn btn-sm btn-white radius-xs m-r-xs ct-dropdown-toggle"\n        remark="每頁顯示筆數"\n      >\n        {{ [$t(\'tl008\'), ipp].join(\': \') }}\n      </button>\n      <div\n        :class="{\'menu-visible\':openMenu==\'modifyIPP\'}"\n        class="dropdown-container-m"\n      >\n        <ul\n          class="dropdown-menu-m"\n          style="max-height: 215px; overflow-y: auto;"\n        >\n          <li\n            v-for="item in 10"\n            :class="{\'selected ct-ripple\':item*5==ipp}"\n            class="dropdown-item-m"\n            @click="onClickModifyIPP(item*5)"\n          >\n            {{ item * 5 }}\n          </li>\n        </ul>\n      </div>\n    </div>\n  </div>\n  <slot></slot>\n</div>\n',
