          tpl: '\n\n<div class="ct-resource gd-xs12" ref="ga001">\n  <!-- 權限設定 -->\n  <div class="ct-row gd-md12 p-lr-sm">\n    <div class="sub-title font-bold subpage-top bg-fresh text-primary text-l">\n      <h3 remark="置頂權限設定">\n        {{ $t("pt001") }}\n      </h3>\n    </div>\n\n    <!-- 置頂權限設定 -->\n    <div  class="sub-title font-bold p-tb-set border-b "\n           remark="置顶权限设置" style="margin-top:30px; margin-left: 15px;">\n      {{ $t("contentTitle_1") }}\n    </div>\n    <div class="form-group-m  p-l" style="margin-bottom : 25px;" >\n      <div class="ct-row p-l">\n        <p class="item-set">*{{ $t("pt002") }}</p>\n      </div>\n      <div class="ct-row p-l">\n        <div class="ct-checkbox-m ct-checkbox-inline-m m-t" style="margin-right: 15px;">\n            <input type="checkbox" \n                  id="chkManager"  \n                  v-model="tempUISetting.managerTag" \n                    checked = "tempUISetting.managerTag"   \n                    disabled    \n                    />\n            <label for="chkManager"></label>\n            <span remark="後台管理者">{{ $t(\'pt003\') }}</span>          \n        </div>\n        <div class="ct-checkbox-m ct-checkbox-inline-m m-t" style="margin-right: 15px;">\n            <input type="checkbox" \n                  id="chkModuleManager"  \n                  v-model="tempUISetting.uditTag" \n                    checked = "tempUISetting.uditTag" \n                    />\n            <label for="chkModuleManager"></label>\n            <span remark="模組管理者">{{ $t(\'pt004\') }}</span>          \n        </div>\n        <div class="ct-checkbox-m ct-checkbox-inline-m m-t" style="margin-right: 15px;">\n            <input type="checkbox" id="chkModuleEditor"  \n                  v-model="tempUISetting.useTag" \n                  checked = "tempUISetting.useTag"\n                  />\n            <label for="chkModuleEditor"></label>\n            <span remark="模組編輯者">{{ $t(\'pt005\') }}</span>          \n        </div>\n      </div>      \n    </div>    \n\n\n    <!-- 檔案附件上傳類型限制 -->\n    <div  class="sub-title font-bold p-tb-set border-b"\n          remark="檔案附件上傳類型限制" style="margin-left: 15px;">\n      {{ $t("fileUpload.title1") }}\n    </div>\n    <div class="m-l-xs  p-l">\n      <div class="form-group-m gd-xs12 p-l" style="margin-bottom: 12px;" >\n        <div class="ct-radio-m">\n          <input id="radio1" type="radio" name="limitFileTag" \n            v-model="tempFileUploadSetting.limitFileTag" v-bind:value=false\n            :checked="tempFileUploadSetting.limitFileTag == false">\n          <label for="radio1">{{ $t("fileUpload.notlimited") }}</label>\n        </div>\n        <div class="ct-radio-m" style="margin-top: 10px;">\n          <input id="radio2" type="radio" name="limitFileTag"\n            v-model="tempFileUploadSetting.limitFileTag" v-bind:value=true\n           :checked="tempFileUploadSetting.limitFileTag == true">\n          <label for="radio2">{{ $t("fileUpload.limit") }}</label>\n        </div>\n      </div>\n      \n      <div class="form-group-m states-danger-m gd-xs12 p-l" style="margin-bottom: 8px;" >\n        <input  type="text"  id="fileName" name="fileName"  alt="fileName" required="required" \n        v-model="tempFileUploadSetting.regFile"/>\n        <label for="fileName" class="input-label" >{{ $t("fileUpload.title2") }}</label>\n        <i class="bar"></i>\n        <div v-if="checkRegex" class="feedback" remark="格式錯誤">{{ $t("fileUpload.errorMessage1") }}</div>\n        <p class="help-block" style="margin-left: 0px" >{{ $t("fileUpload.note2") }}</p>\n      </div>\n      <div class="form-group-m states-danger-m gd-xs12 p-l" style="margin-bottom: 8px;" >\n        <input  type="text"  id="errorMessage" name="errorMessage"  alt="errorMessage" required="required" \n        v-model="tempFileUploadSetting.errorMessage"/>\n        <label for="errorMessage" class="input-label">{{ $t("fileUpload.title3") }}</label>\n        <i class="bar"></i>\n        <p class="help-block" style="margin-left: 0px" >{{ $t("fileUpload.note3") }}</p>\n      </div>  \n    </div>\n\n\n\n\n    <!-- 取消/確認button -->\n    <div class="ct-row">\n      <div class="p-md text-c">\n        <button  @click="cancelSingle" class="ct-btn btn-md radius-xs btn-secondary m-r ct-ripple" remark="取消">\n          <ct-svg class="m-r-xs line-block" svg-src="/pkg_nss/5a9759adef37531ea27bf1b0/assets/cancel-m.svg"></ct-svg>{{ $t(\'pt007\') }}\n          \n        </button>\n        <button  @click="submitSingle" class="ct-btn btn-md radius-xs btn-confirm ct-ripple" remark="確定">\n          \n          <ct-svg class="m-r-xs line-block" svg-src="/pkg_nss/5a9759adef37531ea27bf1b0/assets/confirm-m.svg"></ct-svg>{{ $t(\'pt006\') }}\n        </button>\n      </div>\n    </div>\n    \n  </div>  \n</div>',
